import { test as base, expect } from '@playwright/test';
import { firefox } from 'playwright-extra';
import stealthPlugin from 'puppeteer-extra-plugin-stealth';

const test = base.extend({
  context: async ({ }, use) => {
    const stealth = stealthPlugin();
    firefox.use(stealth);
    
    // Guna folder session Firefox
    const context = await firefox.launchPersistentContext('./yahoo_session_firefox', {
      headless: false,
      firefoxUserPrefs: {
        'dom.webnotifications.enabled': true,
        'permissions.default.desktop-notification': 1,
      }
    });
    
    await use(context);
    await context.close();
  },
});

test('Yahoo Full Flow on Firefox', async ({ page }) => {
  // 1. Pergi ke Settings Notifications
  console.log("Membuka tetapan Yahoo di Firefox...");
  await page.goto('https://beta-mg.mail.yahoo.com/n/settings/notifications');
  
  await page.waitForLoadState('networkidle');
  await page.waitForTimeout(5000); // Tunggu stabil

  // 2. TEKNIK TOGGLE: Focus + Keyboard Space
  // Firefox lebih percaya arahan keyboard berbanding mouse click untuk elemen sensitif
  const toggle = page.getByRole('switch', { name: 'Desktop notifications' });
  
  if (await toggle.isVisible()) {
    console.log("Mencuba toggle guna teknik Keyboard Space...");
    
    // Ambil status sebelum
    const valSebelum = await toggle.getAttribute('aria-checked');
    
    await toggle.focus();
    await page.keyboard.press('Space');
    
    await page.waitForTimeout(2000);
    
    // Ambil status selepas untuk verifikasi
    const valSelepas = await toggle.getAttribute('aria-checked');
    console.log(`Status: ${valSebelum} -> ${valSelepas}`);

    // Jika tak berubah, cuba klik fizikal
    if (valSebelum === valSelepas) {
        console.log("Space gagal, cuba klik paksa...");
        await toggle.click({ force: true });
    }
  }

  // 3. SETTINGS LAIN
  await page.getByText('High-priority emails only').click({ force: true });

  // 4. NAVIGASI KE INBOX UNTUK COMPOSE
  console.log("Kembali ke Inbox...");
  await page.locator('[data-test-id="left-rail-Inbox-icon"]').click();
  
  // Klik Compose
  await page.locator('[data-test-id="left-rail-Compose-icon"]').click();

  // 5. ISI EMAIL
  console.log("Mengisi butiran email...");
  const toField = page.locator('[data-test-id="compose-header-field-to"] input');
  await toField.fill('rasis_test2@yahoo.com');
  await toField.press('Enter');

  await page.getByRole('textbox', { name: 'Subject' }).fill('Test Firefox - ' + new Date().toLocaleTimeString());
  
  // Gunakan locator data-test-id="rte" yang stabil
  await page.locator('[data-test-id="rte"]').fill('Testing automation pada browser Firefox. Harap toggle tadi berfungsi!');

  // 6. HANTAR
  console.log("Menghantar email...");
  await page.locator('[data-test-id="compose-send-button"]').click();

  // 7. PENGESAHAN
  const toast = page.locator('[data-test-id="notifications"]');
  await expect(toast).toContainText('Your message has been sent.', { timeout: 15000 });
  
  console.log("SELESAI! Test di Firefox berjaya.");
});